var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"다음부턴 가급적 피아 식별이 되는 연락 방법을 써 줬으면 좋겠어.","JPN":"次回からはなるべく、味方だけに有効な連絡手段を使ってほしいわね。","ENG":"I'd appreciate it if you could use something more discrete next time around,","TWN":"下次最好能想個可以分辨敵我的連絡方法。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"존 메이슨 씨.","JPN":"頭脳派傭兵の、ジョン・メイソンさん。","ENG":"Mr. John Mason.","TWN":"約翰．梅森先生。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......노력해 보지.","JPN":"……努力しよう。","ENG":"I'll try.","TWN":"……我盡力。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나저나 덤벼든 건 아무래도 리플레이서 붕괴체들뿐인 것 같은데......","JPN":"それより、襲ってきたのはどうやらリプレイサー崩壊体だけみたいだが……","ENG":"By the way, why weren't there anything but Replacer collapsers among the enemies?","TWN":"不論怎樣，殺過來的好像只有克隆崩壞體而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"딱히 지휘관도 없는 것 같고...... 어떻게 된 거지?","JPN":"とくに指揮官もいないみたいだし……どういうことなんだ？","ENG":"And they didn't seem to have a commander either. What happened?","TWN":"他們也沒有指揮官……這是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"최근의 급격한 소모율을 생각하면...... 리플레이서의 인적자원도 한계일 거야.","JPN":"ここのところの急激な兵力消耗を考えると……リプレイサーの人的資源も限界に達してるんだと思うわ。","ENG":"Considering there have been frequent battles as of late, I'm guessing the Replacers are running out of resources.","TWN":"從最近暴增的消耗率來看……克隆集團的人力資源也是有限的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이런 넓은 곳을 일일이 감시하기보단 그냥 붕괴체들을 풀어놓는 게 효율적이겠지.","JPN":"こんなだだっ広いところを監視するより、崩壊体を放しておいたほうが効率良いのでしょうね。","ENG":"It'd be much more efficient for them to just let these collapsers on the loose than set up a proper surveillance system here.","TWN":"比起監視這種廣闊地方的每一個角落，投入克隆崩壞體會比較有效率吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"하지만 그래도 어느 정도의 관리는 필요할 테니까......","JPN":"でも、ある程度の管理は必要でしょうから……","ENG":"However, given that the collapsers need at least a minimum amount of management...","TWN":"但就算這樣，他們還是需要某種程度的管理……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"아마 근처에 거점 역할을 하는 본대가 주둔하고 있을 거야.","JPN":"たぶん近くに拠点の役割になってる本隊が駐屯してるはずよ。","ENG":"It's only right to think there's a garrison base around here.","TWN":"這附近應該有主力部隊駐紮據點。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"なるほどな。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 굳이 놈들과 부딪칠 필요는 없겠지.","JPN":"だったら、あえて奴らと衝突する必要もないだろう。","ENG":"Then we won't have to engage them unnecessarily.","TWN":"那我們沒有必要正面對抗他們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리 목표는 놈들과 싸우는 게 아니라 뉴 오하이오의 무력화니까.","JPN":"俺たちの目標は、奴らと戦うことではなく、ニューオハイオの無力化だからな。","ENG":"Our goal is to neutralize the New Ohio, not to eliminate their forces.","TWN":"我們的目標不是和這些傢伙戰鬥，而是癱瘓新俄亥俄。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 녀석들이 온 방향을 피해서 멀리 돌아가면......","JPN":"奴らが来た方向を避けて、遠回りすれば……","ENG":"I say we go around where they came from, and...","TWN":"我們最好避開這些傢伙過來的方向，繞個遠路……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이봐! 메이슨!","JPN":"おい、メイソン！","ENG":"Hey, Mason!","TWN":"喂！梅森！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이 녀석들 이런 걸 가지고 있는데?","JPN":"こいつらこんなもの持ってるぞ！","ENG":"I found these on one of them!","TWN":"這些傢伙帶著這種東西耶？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아마 움직이는 도중에 가시나 촉수에 딸려온 것 같아.","JPN":"棘や触手にくっついてきたようだ。","ENG":"They probably got stuck on the spikes or tentacles somehow.","TWN":"大概是在移動的過程中，不小心附在刺或是觸手上了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......이건?","JPN":"……これは？","ENG":"These are...","TWN":"……這個？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"응? 뭔데 그래?","JPN":"うん？　どうしたの？","ENG":"Hm? What are they?","TWN":"嗯？怎麼了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......수갑?","JPN":"……手錠？","ENG":"Aren't they handcuffs?","TWN":"……手銬？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래, 강소영인가 하는 경찰 나리가 가지고 있던 것 같은데......","JPN":"そうだ、マエカワなんとかという警察官の所持品のように見えるが……","ENG":"Yeah, they look like what Lieutenant Kang Soyoung was carrying around.","TWN":"沒錯，好像是姜素英他們警察的東西……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......아무래도 본대를 피해서 돌아간다는 계획은 폐기해야 할 것 같군.","JPN":"……本隊を避けて、遠回りする計画はボツになりそうだな。","ENG":"It seems we'll have to scrap our detour plan.","TWN":"……看來避開主力部隊的計畫似乎得作廢了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어째서 이 놈들이 이걸 가지고 있는지는 모르겠지만......","JPN":"こいつらがなぜこれを持ってるかはわからんが……","ENG":"I don't know where they get these,","TWN":"雖然不知道這些傢伙怎麼會有這個……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어쩌면 그 본대라는 곳에 억류되어 있을지도 몰라.","JPN":"ひょっとすると、その本隊に拘束されているのかもしれん。","ENG":"but there's a possibility that the police ladies are being held captive at their base.","TWN":"但他們說不定被關押在敵人主力部隊的地方了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"구하러 갈 생각이야?","JPN":"助けにいくつもり？","ENG":"Are we going to go save them?","TWN":"你要去救他們？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"나쁜 말은 하고 싶지 않지만...... 이미 늦었을지도 몰라.","JPN":"後ろ向きなことは言いたくないけど……もう手遅れかもしれないわよ。","ENG":"I don't want to sound negative, but it might be too late.","TWN":"我也不想說什麼難聽的話……但可能已經來不及了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"물론 그럴 수도 있겠지...... 그래도 알게 된 이상 모른 척 할 수는 없어.","JPN":"無論、そうかもしれん……だが、見て見ぬふりはできない。","ENG":"You may be right, but we can't just find a clue to our allies' whereabouts and pretend that we didn't see it.","TWN":"這當然很有可能……但既然都知道了，我就沒辦法置之不理。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"최소한 확인이라도 해야 해.","JPN":"せめて安否確認だけでも。","ENG":"The least we can do is confirm it.","TWN":"最起碼要去確認一下。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......좋아, 그럼 결정이네.","JPN":"……わかった、じゃあ決まりね。","ENG":"Fine, then it's decided.","TWN":"……好，那就這麼定了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 이동 준비해!","JPN":"みんな、移動に備えろ！","ENG":"Ready to move out, everyone.","TWN":"大家準備移動！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};